import{_ as t,o as r,c as n,ae as a}from"./chunks/framework.BzQXgbNp.js";const m=JSON.parse('{"title":"🎪 伺服器活動系統 (Server Events System)","description":"","frontmatter":{},"headers":[],"relativePath":"Mc-Server-Events.md","filePath":"Mc-Server-Events.md"}'),o={name:"Mc-Server-Events.md"};function s(i,e,l,d,c,v){return r(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="🎪-伺服器活動系統-server-events-system" tabindex="-1">🎪 伺服器活動系統 (Server Events System) <a class="header-anchor" href="#🎪-伺服器活動系統-server-events-system" aria-label="Permalink to &quot;🎪 伺服器活動系統 (Server Events System)&quot;">​</a></h1><p>Craft-Core 伺服器提供全新的 <strong>伺服器活動系統</strong>，包含限時節慶、雙倍經驗/採礦競賽、集字抽獎與全服狂歡節。玩家可隨時在遊戲內或網頁端關注最新的活動動態並領取豐厚獎勵！</p><hr><h2 id="🎮-1-遊戲內活動指令與自動提醒" tabindex="-1">🎮 1. 遊戲內活動指令與自動提醒 <a class="header-anchor" href="#🎮-1-遊戲內活動指令與自動提醒" aria-label="Permalink to &quot;🎮 1. 遊戲內活動指令與自動提醒&quot;">​</a></h2><ul><li><strong><code>/events</code></strong>：在遊戲內聊天欄輸入 <code>/events</code>，系統將即時發送當前所有正在進行中的熱門活動標題、詳細說明、時間與豐厚獎勵！</li><li><strong>登入自動提醒 (Join Broadcast)</strong>：每當您登入伺服器時，系統會在連線成功 2 秒後自動發送彩色限時活動通知，確保您不漏接任何福利訊息。</li></ul><hr><h2 id="🖥️-2-web-dashboard-活動專區-events" tabindex="-1">🖥️ 2. Web Dashboard 活動專區 (<code>/events</code>) <a class="header-anchor" href="#🖥️-2-web-dashboard-活動專區-events" aria-label="Permalink to &quot;🖥️ 2. Web Dashboard 活動專區 (`/events`)&quot;">​</a></h2><p>前往網頁儀表板的 <strong>「🎪 伺服器活動」</strong> 分頁：</p><ol><li><strong>熱門活動看板</strong>：以卡片形式精美展示全服活動，包含活動狀態標籤： <ul><li>🟢 <strong>限時進行中 (Active)</strong>：正開放玩家參與中。</li><li>⏸️ <strong>暫停 (Paused)</strong>：暫時休止。</li><li>⚪ <strong>已結束 (Completed)</strong>：歷屆存檔紀錄。</li></ul></li><li><strong>首頁熱門活動 Alert Banner</strong>：登入儀表板首頁 (<code>HomeView</code>) 頂部會自動浮現動態亮眼的「熱門限時活動 Banner」，可一鍵點擊跳轉至活動專區。</li><li><strong>活動詳情與獎勵</strong>：清楚載入活動規則、開辦時間、結束時間與獎勵項目（如高額遊戲金幣、抽獎鑰匙與稀有道具）。</li></ol><hr><h2 id="🛠️-3-管理員發布與維護專區-admin-event-management" tabindex="-1">🛠️ 3. 管理員發布與維護專區 (Admin Event Management) <a class="header-anchor" href="#🛠️-3-管理員發布與維護專區-admin-event-management" aria-label="Permalink to &quot;🛠️ 3. 管理員發布與維護專區 (Admin Event Management)&quot;">​</a></h2><p>管理員在網頁儀表板 (<code>/events</code> 或 <code>/admin</code>) 可進行以下管理：</p><ul><li><strong>發布新活動</strong>：點選「發布新伺服器活動」按鈕，填寫活動標題、詳細內容、起訖時間與獎勵說明。</li><li><strong>即時狀態切換</strong>：可隨時一鍵切換活動狀態（啟用/暫停/結束），系統將同步即時更新遊戲內與網頁端。</li><li><strong>編輯與刪除</strong>：隨時修改活動條款或刪除過期活動。</li></ul>',13)])])}const h=t(o,[["render",s]]);export{m as __pageData,h as default};
